INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (233, 155345, 10, 549, '感觉', '我的心时而在西伯利亚，时而在撒哈拉―时冷时热。因为对你的思念就像那无形的几何平面―看不见，摸不着，却没有边。日子一天又一天，就像那小数循环；我的爱一点又一点，组成那几何直线，一直延伸到天边的那个天。
<br>   思绪，远远近近深深浅浅浓浓淡淡；情丝，厚厚薄薄稀稀密密地爬满了我的胸坎。千般愁绪，万种情思，交织成大大小小苦苦甜甜的无眠，从头顶浸透到脚尖，让人沉醉得痴痴呆呆疯疯颠颠。那景象，似万花筒，令人目眩的风景一闪现；那滋味，像五味瓶，酸甜苦辣麻俱全。夜夜轻荡的月亮啊，满载我碧绿的梦幻，带着多多少少花花绿绿的企盼！！！！~~~~~~~~~~~~', '我的心时而在西伯利亚，时而在撒哈拉―时冷时热。因为对你的思念就像那无形的几何平面―看不见，摸不着，却没有边。日子一天又一天，就像那小数循环；我的爱一点又一点，组成那几何直线，一直延伸到天边的那个天。

思绪，远远近近深深浅浅浓浓淡淡；情丝，厚厚薄薄稀稀密密地爬满了我的胸坎。千般愁绪，万种情思，交织成大大小小苦苦甜甜的无眠，从头顶浸透到脚尖，让人沉醉得痴痴呆呆疯疯颠颠。那景象，似万花筒，令人目眩的风景一闪现；那滋味，像五味瓶，酸甜苦辣麻俱全。夜夜轻荡的月亮啊，满载我碧绿的梦幻，带着多多少少花花绿绿的企盼！！！！~~~~~~~~~~~~', '命中注定上帝说原谅你要我们粘在一起，还是爱你没办法讨厌你也许是爱的引力^-^

